import React, { useEffect } from "react"
import useData, { getPlansData, getTotalAmount } from "../useData"
import useSplitStore from "../useSplitStore"

export function Plan({ label, duration, handleClick }) {
    return (<button className="text-blue-800 rounded-lg bg-blue-400" onClick={handleClick}>
        <div>{label}</div>
        <div>{duration + '' + 'months'}</div>
    </button>
    )
}
function Plans() {
    const { data, loading, error } = useData(getPlansData)
    const { setPlans, setSelectedPlan } = useSplitStore((s) => s)

    useEffect(() => {
        if (data) {
            setPlans(data)
        }
    }, [data])

    function handlePlanClick(plan) {
        setSelectedPlan(plan)
    }
    if (loading) {
        return <div>Loading...</div>
    }
    if (error) {
        return <div>{error.message}</div>
    }
    if (data) {
        return (
            <div className="grid grid-cols-4 gap-2">
                {
                    data.map((plan) => {
                        return (<Plan key={plan.id} {...plan} handleClick={() => handlePlanClick(plan)} />)
                    })
                }
            </div>
        )
    }
    return null
}

export default Plans
